// Static, client-side seed list of supported carparks (10 original T1-validated
// seeds plus verified coverage-expansion candidates). Powers search (no network
// involved) and doubles as the share-link whitelist (design doc Security
// section: "the frontend validates the carpark_id from a share-link URL
// against the same whitelist client-side"). Generated by
// scripts/regen_seed_lists.py from data/carpark_coverage_map.json -- do not
// hand-edit the SEED_CARPARKS array, re-run the generator instead. Must match
// db/schema.sql's carparks table (server-side canonical copy).

export interface SeedCarpark {
  id: string;
  /** Raw LTA Development name -- the server-side canonical name (db/schema.sql). */
  name: string;
  /**
   * OneMap building name if resolved, else equal to `name` (never a fabricated
   * name -- "honest beats invented"). Prefer this for anything user-facing;
   * `name` remains for exact matching against the server/share-link contract.
   */
  displayName: string;
  /** 6-digit postal code, present only if OneMap resolved this carpark. */
  postalCode?: string;
  latitude?: number;
  longitude?: number;
}

